import{_ as a,o as t,c as s,a2 as n}from"./chunks/framework._O8Cueap.js";const v=JSON.parse('{"title":"Conversations","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/conversations.md","filePath":"concepts/conversations.md"}'),i={name:"concepts/conversations.md"};function o(r,e,l,c,d,h){return t(),s("div",null,[...e[0]||(e[0]=[n('<h1 id="conversations" tabindex="-1">Conversations <a class="header-anchor" href="#conversations" aria-label="Permalink to &quot;Conversations&quot;">​</a></h1><p>Conversations let users chat directly with an agent outside the workflow engine.</p><h2 id="what-a-conversation-is" tabindex="-1">What a Conversation Is <a class="header-anchor" href="#what-a-conversation-is" aria-label="Permalink to &quot;What a Conversation Is&quot;">​</a></h2><ul><li>A conversation is a persisted thread between one user and one selected agent.</li><li>Each conversation belongs to a workspace and is recorded in the database.</li><li>The conversation history is stored as ordered <code>user</code> and <code>assistant</code> messages, so users can leave and resume later.</li></ul><h2 id="starting-a-conversation" tabindex="-1">Starting a Conversation <a class="header-anchor" href="#starting-a-conversation" aria-label="Permalink to &quot;Starting a Conversation&quot;">​</a></h2><ul><li>Open <strong>Conversations</strong> from the workspace navigation and create a new thread.</li><li>Choose one active agent from the available agent list.</li><li>Optionally provide a title; otherwise OAO generates one automatically.</li><li>Agent detail pages include a <strong>Start Conversation</strong> shortcut that preselects that agent.</li></ul><h2 id="interactive-behavior" tabindex="-1">Interactive Behavior <a class="header-anchor" href="#interactive-behavior" aria-label="Permalink to &quot;Interactive Behavior&quot;">​</a></h2><ul><li>Messages are stored immediately when the user sends them.</li><li>The assistant response is created as a pending message and then streamed into the UI as deltas arrive.</li><li>Conversation pages subscribe to server-sent events (SSE), so the transcript updates while the agent is still responding.</li><li>Only one assistant turn can run at a time for a conversation.</li></ul><h2 id="agent-context" tabindex="-1">Agent Context <a class="header-anchor" href="#agent-context" aria-label="Permalink to &quot;Agent Context&quot;">​</a></h2><ul><li>Conversations use the selected agent&#39;s markdown instructions, skills, built-in tools, MCP servers, and scoped variables.</li><li>Workflow-specific tools such as workflow editing and self-scheduling are intentionally excluded from conversation sessions because there is no workflow execution context.</li><li>The same per-agent session lock used by workflow steps also applies to conversations, so an agent cannot run conflicting Copilot sessions at the same time.</li></ul><h2 id="persistence-model" tabindex="-1">Persistence Model <a class="header-anchor" href="#persistence-model" aria-label="Permalink to &quot;Persistence Model&quot;">​</a></h2><ul><li><code>conversations</code> stores the thread header, selected agent, and timestamps.</li><li><code>conversation_messages</code> stores each turn, its status, any assistant error, and assistant metadata such as model/tool trace.</li><li>If an agent is deleted later, the existing conversation remains readable, but new turns are disabled.</li></ul><h2 id="typical-use-cases" tabindex="-1">Typical Use Cases <a class="header-anchor" href="#typical-use-cases" aria-label="Permalink to &quot;Typical Use Cases&quot;">​</a></h2><ul><li>Ask an agent ad hoc questions before formalizing the task into a workflow.</li><li>Validate an agent&#39;s prompt design interactively from its detail page.</li><li>Keep a lightweight working thread with an agent while still using workflows for repeatable automation.</li></ul>',14)])])}const g=a(i,[["render",o]]);export{v as __pageData,g as default};
